$_LANG['cloudxemail_security_5_description_13']  = "  Warum den Eingangsfilter von SpamExperts wählen?";
$_LANG['cloudxemail_security_5_description_14'] = "Die Filterung eingehender E-Mails filtert alle eingehenden E-Mails und eliminiert Spam und Viren, bevor diese Bedrohungen Ihr Netzwerk mit einer Genauigkeitsrate von nahezu 100 % erreichen. Das umfangreiche Bedienfeld ermöglicht es Ihnen, die volle Kontrolle zu behalten. Falls Ihr E-Mail-Server ausfällt, wird Ihre E-Mail außerdem in die Warteschlange gestellt. Auf E-Mails in der Warteschlange kann über die Webschnittstelle zugegriffen, gelesen und darauf geantwortet werden, was die Kontinuität Ihrer eingehenden E-Mails erhöht!";
$_LANG['cloudxemail_security_5_description_15'] = "Warum brauchen Sie einen professionellen Eingangsfilter?";
