$_LANG['cloudxemail_security_6_description_6']  = "Verbessern Sie die Handhabung von Missbrauch";
$_LANG['cloudxemail_security_6_description_7'] = " Was ist ausgehende Filterung?";
$_LANG['cloudxemail_security_6_description_8'] = "Die Filterung ausgehender E-Mails ist unerlässlich, um den Ruf Ihrer IT-Infrastruktur zu schützen und sicherzustellen, dass alle Ihre ausgehenden E-Mails sicher dort ankommen, wo sie hingehören. Diese professionelle Lösung verhindert, dass Spam und Viren Ihr Netzwerk verlassen, und verhindert, dass Ihre IP(s) jemals wieder auf die schwarze Liste gesetzt werden. Darüber hinaus bietet Ihnen der Ausgangsfilter von SpamExperts die Berichte und Tools, um kompromittierte Konten zu erkennen und Spam-Benutzer zu sperren.";
$_LANG['cloudxemail_security_6_description_9'] = "Warum brauchst Du es?";
