$_LANG['cloudx_hosting_servers_section_7_description_1'] = "Was ist ein SSL-Zertifikat?";
$_LANG['cloudx_hosting_servers_section_7_description_2'] = "Ein SSL-Zertifikat ist ein digitales Zertifikat, das die Identität einer Website authentifiziert und eine verschlüsselte Verbindung ermöglicht. SSL steht für Secure Sockets Layer, ein Sicherheitsprotokoll, das eine verschlüsselte Verbindung zwischen einem Webserver und einem Webbrowser herstellt.";
